import{_ as t,c as r,o as n,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.53: User Plugin Priority, ACP Session Usage Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.53.md","filePath":"en/changelog/v1.1.53.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.1.53.md"};function s(l,a,d,h,p,u){return n(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-53-user-plugin-priority-acp-session-usage-tracking" tabindex="-1">v1.1.53: User Plugin Priority, ACP Session Usage Tracking <a class="header-anchor" href="#v1-1-53-user-plugin-priority-acp-session-usage-tracking" aria-label="Permalink to “v1.1.53: User Plugin Priority, ACP Session Usage Tracking”">​</a></h1><p><strong>Release Date</strong>: February 05, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update allows user plugins to override built-in plugins, adds ACP session usage tracking, fixes unhandled errors when aborting messages, and improves file operations and terminal stability in desktop.</p><hr><h2 id="new-feature-user-plugins-override-built-in-plugins" tabindex="-1">New Feature: User Plugins Override Built-in Plugins <a class="header-anchor" href="#new-feature-user-plugins-override-built-in-plugins" aria-label="Permalink to “New Feature: User Plugins Override Built-in Plugins”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When user plugins and built-in plugins provide the same provider, user plugins now take priority.</p><h3 id="what-s-the-use" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>If you&#39;re not satisfied with built-in plugin behavior, you can write your own plugin to replace it. For example, if you want to customize a provider&#39;s authentication method, just create a user plugin with the same name.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>Create a plugin file with the same name as the built-in plugin in <code>.opencode/plugins/</code> or <code>~/.config/opencode/plugins/</code>, and OpenCode will automatically use your version.</p><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/12a-plugins-basics.html">Plugins Basics</a></p><hr><h2 id="new-feature-acp-session-usage-tracking" tabindex="-1">New Feature: ACP Session Usage Tracking <a class="header-anchor" href="#new-feature-acp-session-usage-tracking" aria-label="Permalink to “New Feature: ACP Session Usage Tracking”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>ACP (Agent Communication Protocol) now supports session-level usage tracking.</p><h3 id="what-s-the-use-1" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use-1" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>If you use OpenCode through IDE extensions (like VS Code), you can now see token usage statistics for each session.</p><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/08b-acp.html">ACP Protocol</a></p><hr><h2 id="improvement-plugin-loading-order" tabindex="-1">Improvement: Plugin Loading Order <a class="header-anchor" href="#improvement-plugin-loading-order" aria-label="Permalink to “Improvement: Plugin Loading Order”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>User plugins now load after built-in plugins, ensuring user plugins can correctly override built-in behavior.</p><hr><h2 id="bug-fix-unhandled-error-when-aborting-messages" tabindex="-1">Bug Fix: Unhandled Error When Aborting Messages <a class="header-anchor" href="#bug-fix-unhandled-error-when-aborting-messages" aria-label="Permalink to “Bug Fix: Unhandled Error When Aborting Messages”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When aborting with queued messages, unhandled errors could be triggered.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Abort operations now correctly handle queued messages, no more unhandled errors.</p><hr><h2 id="improvement-desktop" tabindex="-1">Improvement: Desktop <a class="header-anchor" href="#improvement-desktop" aria-label="Permalink to “Improvement: Desktop”">​</a></h2><h3 id="file-external-open" tabindex="-1">File External Open <a class="header-anchor" href="#file-external-open" aria-label="Permalink to “File External Open”">​</a></h3><p>Added button to open files in external applications.</p><h3 id="prompt-input-improvement" tabindex="-1">Prompt Input Improvement <a class="header-anchor" href="#prompt-input-improvement" aria-label="Permalink to “Prompt Input Improvement”">​</a></h3><p>Close comment button is now visible in prompt input. Prompt input automatically hides when there are permission requests or questions.</p><h3 id="file-tree-collapse" tabindex="-1">File Tree Collapse <a class="header-anchor" href="#file-tree-collapse" aria-label="Permalink to “File Tree Collapse”">​</a></h3><p>File tree can now be collapsed independently without affecting other panels.</p><h3 id="modified-file-color-contrast" tabindex="-1">Modified File Color Contrast <a class="header-anchor" href="#modified-file-color-contrast" aria-label="Permalink to “Modified File Color Contrast”">​</a></h3><p>Modified file color contrast improved for easier identification.</p><hr><h2 id="improvement-tui" tabindex="-1">Improvement: TUI <a class="header-anchor" href="#improvement-tui" aria-label="Permalink to “Improvement: TUI”">​</a></h2><h3 id="dialog-mouse-exit" tabindex="-1">Dialog Mouse Exit <a class="header-anchor" href="#dialog-mouse-exit" aria-label="Permalink to “Dialog Mouse Exit”">​</a></h3><p>The &quot;esc&quot; label in dialogs now supports mouse click to exit, not just keyboard.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using custom plugins</td><td>✅ Recommended</td></tr><tr><td>Using OpenCode via IDE</td><td>✅ Recommended</td></tr><tr><td>Desktop users</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',49),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Load user plugins after built-in plugins</li><li>Fix unhandled errors when aborting with queued messages</li><li>User plugins override built-in plugins for the same provider (@rmk40)</li><li>Move Codex 5.3 model definition to plugin to avoid showing unsupported model to other users</li><li>Add session usage tracking to ACP (@SteffenDE)</li><li>Update transforms for GPT-5.3</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Allow mouse escape via &quot;esc&quot; labels in dialogs (@AksharP5)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Make close comment button visible in prompt input (@alexyaroshuk)</li><li>Hide prompt input when there are permissions requests or questions</li><li>More terminal stability fixes</li><li>Modified file color contrast in app for better visibility</li><li>Add button to open files in external applications</li><li>Allow toggling file tree closed independently</li><li>Stop showing SessionSkeleton on new workspace (@dbpolito)</li><li>Set workspace name earlier to improve creation and deletion (@dbpolito)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=t(o,[["render",s]]);export{m as __pageData,g as default};
